import sys

def calculate_total_angle(r, f):
    """Calculate the total angle rotated by the pan."""
    rate = 180 / r  # degrees per second
    total_angle = rate * f  # total angle in degrees
    return total_angle

def determine_final_position(total_angle):
    """Determine the final position of the blueberry side."""
    # Normalize the total angle to be within [0, 360)
    total_angle = total_angle % 360

    # Determine the angle when the pan stops
    final_angle = total_angle % 180

    if final_angle > 90:
        final_angle = 180 - final_angle

    # Decide whether the pan returns to horizontal via a forward or backward rotation
    if total_angle % 180 > 90:
        direction = 'backward'
    else:
        direction = 'forward'

    # Determine the final position based on the angle and direction
    if direction == 'forward':
        if final_angle <= 90:
            return 'up' if total_angle % 360 <= 180 else 'down'
        else:
            return 'down'
    else:
        if final_angle <= 90:
            return 'down' if total_angle % 360 <= 180 else 'up'
        else:
            return 'up'

def main():
    try:
        r, f = map(int, sys.stdin.readline().strip().split())
        total_angle = calculate_total_angle(r, f)
        final_position = determine_final_position(total_angle)
        print(final_position)
    except Exception as e:
        # In a real application, you might want to log this error
        pass

if __name__ == "__main__":
    main()
