from sys import stdin, stdout

def read_input():
    n = int(stdin.readline().strip())
    tubes = []
    for _ in range(n + 1):
        b, m, t = map(int, stdin.readline().strip().split())
        tubes.append([b, m, t])
    return n, tubes

def is_color_tubes(tubes):
    for tube in tubes:
        if tube[0] != 0 and tube[0] == tube[1] == tube[2]:
            continue
        if tube[0] == 0 and tube[1] == 0 and tube[2] == 0:
            continue
        return False
    return True

def get_top_color(tube):
    for color in reversed(tube):
        if color != 0:
            return color
    return 0

def get_next_states(tubes):
    next_states = []
    for i in range(len(tubes)):
        top_color = get_top_color(tubes[i])
        if top_color == 0:
            continue
        for j in range(len(tubes)):
            if i == j:
                continue
            if tubes[j][2] == 0:
                new_tubes = [list(tube) for tube in tubes]
                new_tubes[i][new_tubes[i].index(top_color)] = 0
                new_tubes[j][2] = top_color
                next_states.append((new_tubes, (i + 1, j + 1)))
    return next_states

def heuristic(tubes):
    h = 0
    for tube in tubes:
        if tube[0] == tube[1] == tube[2] != 0:
            h += 3
        elif tube[0] == tube[1] != 0 and tube[2] == 0:
            h += 2
        elif tube[0] == tube[1] == tube[2] == 0:
            h += 0
        elif tube[0] != 0 and tube[1] == tube[2] == 0:
            h += 1
        else:
            h -= 3
    return h

def ids(n, tubes):
    max_depth = 0
    while max_depth <= 20 * n:
        result = dls(tubes, max_depth)
        if result is not None:
            return result
        max_depth += 1
    return None

def dls(tubes, max_depth):
    stack = deque([(tubes, [], 0, heuristic(tubes))])
    visited = set()
    visited.add(tuple(tuple(tube) for tube in tubes))
    while stack:
        current_tubes, moves, depth, _ = stack.pop()
        if is_color_tubes(current_tubes):
            return len(moves), moves
        if depth < max_depth:
            for next_tubes, move in get_next_states(current_tubes):
                next_tubes_tuple = tuple(tuple(tube) for tube in next_tubes)
                if next_tubes_tuple not in visited:
                    visited.add(next_tubes_tuple)
                    stack.append((next_tubes, moves + [move], depth + 1, heuristic(next_tubes)))
    return None

def main():
    n, tubes = read_input()
    result = ids(n, tubes)
    if result is not None:
        num_moves, moves = result
        stdout.write(str(num_moves) + '\n')
        for move in moves:
            stdout.write(f'{move[0]} {move[1]}\n')
    else:
        stdout.write('No solution found\n')

if __name__ == '__main__':
    main()
