from collections import deque

def is_valid_state(state):
    """Check if the given state is a valid Color Tubes state."""
    for tube in state:
        if len(tube) == 3 and len(set(tube)) != 1:
            return False
    return True

def get_next_states(state):
    """Generate all possible next states by making a move."""
    next_states = []
    num_tubes = len(state)
    for src in range(num_tubes):
        if state[src]:
            ball = state[src][-1]
            for dst in range(num_tubes):
                if src != dst and len(state[dst]) < 3:
                    new_state = [list(tube) for tube in state]
                    new_state[src].pop()
                    new_state[dst].append(ball)
                    next_states.append(tuple(tuple(tube) for tube in new_state))
    return next_states

def iddfs(initial_state):
    """Perform Iterative Deepening Depth-First Search to find a solution."""
    num_tubes = len(initial_state)
    max_depth = 20 * (num_tubes - 1)
    for depth_limit in range(max_depth + 1):
        stack = deque([(initial_state, [])])
        visited = set()
        while stack:
            state, moves = stack.pop()
            if state in visited:
                continue
            visited.add(state)
            if is_valid_state(state):
                return moves
            if len(moves) == depth_limit:
                continue
            for next_state in get_next_states(state):
                new_moves = moves + [(len(initial_state) - list(state).index(next_state[-1]), len(initial_state) - list(state).index(next_state[-2])) if len(next_state[-1]) > len(state[-1]) else (len(initial_state) - list(state).index(next_state[-2]), len(initial_state) - list(state).index(next_state[-1]))]
                new_moves = moves + [(list(state).index(state[src]) + 1, list(state).index(next_state[dst]) + 1) for src, dst in [(src, dst) for src in range(num_tubes) for dst in range(num_tubes) if src != dst and state[src] and len(state[dst]) < 3 and state[src][-1] == next_state[dst][-1]]]
                stack.append((next_state, new_moves))
        if depth_limit == max_depth:
            return None

def main():
    """Read input, solve the problem, and print the solution."""
    num_colors = int(input())
    num_tubes = num_colors + 1
    initial_state = []
    for _ in range(num_tubes):
        tube = list(map(int, input().split()))
        initial_state.append(tuple(ball for ball in tube if ball != 0))
    solution = iddfs(tuple(initial_state))
    if solution is None:
        print("No solution found")
    else:
        print(len(solution))
        for move in solution:
            print(*move)

if __name__ == "__main__":
