    tubes = []
    for _ in range(n + 1):
        b, m, t = map(int, input().split())
        tubes.append([b, m, t])
    return n, tubes

def is_completable(tube):
    non_zero_balls = [ball for ball in tube if ball != 0]
    return len(set(non_zero_balls)) <= 1

def count_moves_to_complete(tube):
    non_zero_balls = [ball for ball in tube if ball != 0]
    if len(set(non_zero_balls)) == 1:
        return 0
    return 3 - len(non_zero_balls)

def make_move(tubes, source, destination, moves):
    top_ball = tubes[source][-1]
    tubes[source][-1] = 0
    for i in range(3):
        if tubes[destination][i] == 0:
            tubes[destination][i] = top_ball
            moves.append((source + 1, destination + 1))
            return

def find_completable_tube(tubes):
    min_moves = float('inf')
    completable_tube_index = -1
    for i, tube in enumerate(tubes):
        if is_completable(tube):
            continue
        moves_to_complete = count_moves_to_complete(tube)
        if moves_to_complete < min_moves and moves_to_complete > 0:
            min_moves = moves_to_complete
            completable_tube_index = i
    return completable_tube_index

def is_solved(tubes):
    for tube in tubes:
        non_zero_balls = [ball for ball in tube if ball != 0]
        if len(non_zero_balls) > 0 and len(set(non_zero_balls)) > 1:
            return False
    return True

def solve(n, tubes):
    moves = []
    while not is_solved(tubes):
        completable_tube_index = find_completable_tube(tubes)
        if completable_tube_index == -1:
            break
        completable_tube = tubes[completable_tube_index]
        top_ball = completable_tube[-1]
        while top_ball == 0:
