            top_ball = completable_tube[-1]
        for i, tube in enumerate(tubes):
            if i == completable_tube_index:
                continue
            if tube[-1] == 0 and top_ball != 0 and (tube[0] == top_ball or tube[0] == 0):
                make_move(tubes, completable_tube_index, i, moves)
                break
        else:
            for i, tube in enumerate(tubes):
                if i == completable_tube_index:
                    continue
                if tube[-1] == 0:
                    make_move(tubes, completable_tube_index, i, moves)
                    break
    for i, tube in enumerate(tubes):
        if tube[-1] != 0 and tube[-2] == 0:
            for j, other_tube in enumerate(tubes):
                if other_tube[-1] == 0 and other_tube[-2] == 0:
