    top_color_u = get_top_color(tubes[u])
    tubes[v][get_num_balls(tubes[v])] = top_color_u
    tubes[u][tubes[u].index(top_color_u)] = 0
    moves.append((u + 1, v + 1))

def solve(n, tubes):
    moves = []
    # Phase 1: Clear mixed tubes
    while True:
        changed = False
        for u in range(n + 1):
            if not is_valid(tubes[u]) and is_movable(tubes[u]):
                top_color_u = get_top_color(tubes[u])
                for v in range(n + 1):
