                            move_ball(tubes, u, v, moves)
                            changed = True
                            break
                if changed:
                    break
        if not changed:
            break

    # Phase 2: Complete valid states
    while True:
        changed = False
        for u in range(n + 1):
            if not is_valid(tubes[u]) and is_movable(tubes[u]):
                top_color_u = get_top_color(tubes[u])
