import sys
import random

def read_input():
    n = int(sys.stdin.readline().strip())
    tubes = []
    for _ in range(n + 1):
        tube = list(map(int, sys.stdin.readline().strip().split()))
        tubes.append(tube)
    return n, tubes

def is_valid_state(tubes):
    for tube in tubes:
        if len([x for x in tube if x != 0]) > 0 and len(set([x for x in tube if x != 0])) != 1:
            return False
    return True

def count_valid_tubes(tubes):
    count = 0
    for tube in tubes:
        if len([x for x in tube if x != 0]) > 0 and len(set([x for x in tube if x != 0])) == 1:
            count += 1
    return count

def get_top_ball(tube):
    for i in range(2, -1, -1):
        if tube[i] != 0:
            return tube[i], i
    return 0, -1

def make_move(tubes, src, dst):
    top_ball, idx = get_top_ball(tubes[src])
    if top_ball == 0:
        return False
    if len([x for x in tubes[dst] if x != 0]) == 3:
        return False
    tubes[src][idx] = 0
    for i in range(3):
        if tubes[dst][i] == 0:
            tubes[dst][i] = top_ball
            return True

def undo_move(tubes, src, dst, prev_state):
    for i in range(3):
        if tubes[dst][i] != prev_state[dst][i]:
            tubes[src][prev_state[src].index(0)] = tubes[dst][i]
            tubes[dst][i] = prev_state[dst][i]
            return

def iterative_improvement(n, tubes):
    moves = []
    max_moves = 20 * n
    current_valid_tubes = count_valid_tubes(tubes)
    while len(moves) < max_moves:
        if is_valid_state(tubes):
            break
        tube_indices = list(range(n + 1))
        random.shuffle(tube_indices)
        made_move = False
        for src in tube_indices:
            top_ball, _ = get_top_ball(tubes[src])
            if top_ball == 0:
                continue
            for dst in tube_indices:
                if src == dst:
                    continue
                prev_state = [tube.copy() for tube in tubes]
                if make_move(tubes, src, dst):
                    new_valid_tubes = count_valid_tubes(tubes)
                    if new_valid_tubes > current_valid_tubes:
                        moves.append((src + 1, dst + 1))
                        current_valid_tubes = new_valid_tubes
                        made_move = True
                        break
                    else:
                        undo_move(tubes, src, dst, prev_state)
            if made_move:
                break
    return moves

def main():
    n, tubes = read_input()
    moves = iterative_improvement(n, tubes)
    print(len(moves))
    for move in moves:
        print(move[0], move[1])

if __name__ == "__main__":
