def double_up():
    n = int(input().strip())
    sequence = list(map(int, input().strip().split()))

    # Initialize a 2D table to store the maximum number that can be obtained for each subsequence.
    dp = [[0] * n for _ in range(n)]

    # Initialize the diagonal of the table with the input sequence.
    for i in range(n):
        dp[i][i] = sequence[i]

    # Fill the table by considering all possible subsequences.
    for length in range(2, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1

            # Initialize the maximum number for the current subsequence.
            max_num = 0

            # Check if the first and last numbers are the same and can be merged.
            if dp[i][i] == dp[j][j]:
                # If the subsequence has only two elements, merge them.
                if length == 2:
                    max_num = dp[i][i] * 2
                # If the subsequence has more than two elements, check if the numbers in between can be removed or merged.
                else:
                    for k in range(i + 1, j):
                        if dp[i + 1][k] == 0 or dp[k + 1][j] == 0:
                            max_num = max(max_num, dp[i][i] * 2)
                        else:
                            max_num = max(max_num, dp[i + 1][k] + dp[k + 1][j] if dp[i + 1][k] == dp[k + 1][j] else 0)

            # Check all possible splits of the subsequence.
            for k in range(i, j):
                max_num = max(max_num, dp[i][k], dp[k + 1][j])

            dp[i][j] = max_num

    # The final answer is stored in the table for the entire sequence.
    print(dp[0][n - 1])

