import sys

def read_input():
    n = int(sys.stdin.readline().strip())
    sequence = list(map(int, sys.stdin.readline().strip().split()))
    return n, sequence

def double_up(sequence):
    memo = {}
    def recursive_double_up(left, right):
        if (left, right) in memo:
            return memo[(left, right)]

        if left == right:
            memo[(left, right)] = sequence[left]
            return sequence[left]

        max_value = 0
        # Try to merge adjacent identical numbers
        for mid in range(left, right):
            if sequence[mid] == sequence[mid + 1]:
                new_sequence = sequence[:]
                new_sequence[mid] *= 2
                new_sequence.pop(mid + 1)
                max_value = max(max_value, recursive_double_up(left, mid) if mid == right - 1 else recursive_double_up(left, mid) if len(new_sequence[left:right+1]) == 1 else recursive_double_up(left, right - 1))

        # Try to remove a number
        for i in range(left, right + 1):
            if left == right:
                max_value = max(max_value, sequence[left])
            else:
                max_value = max(max_value, recursive_double_up(left, i - 1) if i > left else 0, recursive_double_up(i + 1, right) if i < right else 0)

        # If we can directly return the max of the subsequence
        max_value = max(max_value, max(sequence[left:right + 1]))

        memo[(left, right)] = max_value
        return max_value

    return recursive_double_up(0, len(sequence) - 1)

def main():
    n, sequence = read_input()
    result = double_up(sequence)
    print(result)

