import sys

class SegmentTree:
    def __init__(self, nums):
        self.n = len(nums)
        self.tree = [(0, 0)] * (4 * self.n)
        self.build_tree(nums, 0, 0, self.n - 1)

    def build_tree(self, nums, node, start, end):
        if start == end:
            self.tree[node] = (nums[start], nums[start])
        else:
            mid = (start + end) // 2
            self.build_tree(nums, 2 * node + 1, start, mid)
            self.build_tree(nums, 2 * node + 2, mid + 1, end)
            left_value, left_count = self.tree[2 * node + 1]
            right_value, right_count = self.tree[2 * node + 2]
            if left_value == right_value:
                self.tree[node] = (left_value * 2, left_count + right_count)
            else:
                self.tree[node] = (max(left_value, right_value), 0)

    def query(self, node, start, end, left, right):
        if start > right or end < left:
            return (0, 0)
        if left <= start and end <= right:
            return self.tree[node]
        mid = (start + end) // 2
        left_value, left_count = self.query(2 * node + 1, start, mid, left, right)
        right_value, right_count = self.query(2 * node + 2, mid + 1, end, left, right)
        if left_value == right_value:
            return (left_value * 2, left_count + right_count)
        else:
            return (max(left_value, right_value), 0)


def main():
    n = int(sys.stdin.readline().strip())
    nums = list(map(int, sys.stdin.readline().strip().split()))
    segment_tree = SegmentTree(nums)
    result, _ = segment_tree.query(0, 0, n - 1, 0, n - 1)
    print(result)

if __name__ == "__main__":
    main()
