def double_up_game(seq):
    """Recursive function to determine the maximum value obtainable from a given sequence."""
    n = len(seq)
    memo = {}

    def recurse(start, end):
        """Recurse on a subsequence from start to end."""
        if (start, end) in memo:
            return memo[(start, end)]

        if start == end:
            return seq[start]

        # Try to merge the first two elements if they are the same
        if start + 1 <= end and seq[start] == seq[start + 1]:
            merged = recurse(start + 2, end) + seq[start] * 2
        else:
            merged = 0

        # Try removing the first element
        removed = recurse(start + 1, end)

        # Store the maximum result in memo
        result = max(merged, removed)
        memo[(start, end)] = result
        return result

    return recurse(0, n - 1)


def main():
    """Read input and print the result."""
    n = int(input().strip())
    seq = list(map(int, input().strip().split()))
    result = double_up_game(seq)
    print(result)


