import sys

class SegmentTree:
    def __init__(self, nums):
        self.n = len(nums)
        self.tree = [(0, 0, 0) for _ in range(4 * self.n)]
        self.build_tree(nums, 0, 0, self.n - 1)

    def build_tree(self, nums, node, start, end):
        if start == end:
            self.tree[node] = (nums[start], nums[start], nums[start])
        else:
            mid = (start + end) // 2
            self.build_tree(nums, 2 * node + 1, start, mid)
            self.build_tree(nums, 2 * node + 2, mid + 1, end)
            left_max, left_merge, left_sum = self.tree[2 * node + 1]
            right_max, right_merge, right_sum = self.tree[2 * node + 2]
            self.tree[node] = self.merge(left_max, left_merge, left_sum, right_max, right_merge, right_sum)

    def merge(self, left_max, left_merge, left_sum, right_max, right_merge, right_sum):
        max_val = max(left_max, right_max)
        merge_val = left_merge
        if left_merge == left_sum and left_sum == right_merge:
            merge_val = left_sum + right_sum
        sum_val = left_sum + right_sum
        return (max(max_val, merge_val), merge_val, sum_val)

    def query_max(self):
        return self.tree[0][0]

def main():
    n = int(sys.stdin.readline().strip())
    nums = list(map(int, sys.stdin.readline().strip().split()))
    segment_tree = SegmentTree(nums)
    print(segment_tree.query_max())

if __name__ == "__main__":
