def is_feasible(cleanings, n, mess, capacity, visits):
    total_mess = 0
    cleaning_count = 0
    for day in range(n):
        total_mess += mess[day]
        if cleaning_count < cleanings and total_mess >= capacity[day]:
            total_mess -= capacity[day]
            cleaning_count += 1
        if day + 1 in visits and total_mess > 0:
            return False
    return True

def binary_search(n, mess, capacity, visits):
    low, high = 0, n
    while low <= high:
        mid = (low + high) // 2
        if is_feasible(mid, n, mess, capacity, visits):
            high = mid - 1
        else:
            low = mid + 1
    return low if low <= n else -1

def main():
