                continue
            new_size = size / 2
            time = dp[size] + h * math.log(2)
            if new_size not in new_dp or time < new_dp[new_size]:
                new_dp[new_size] = time
        dp = new_dp

    # Find the minimum time to reach the target average piece size
    min_time = float('inf')
    for size in dp:
        if size >= t:
            min_h = min([h for m, h in filtered_blades if size <= m] or [float('inf')])
            if min_h != float('inf'):
                time = dp[size] + min_h * math.log(size / t, 2)
                if time < min_time:
                    min_time = time

    if min_time == float('inf'):
        print(-1)
    else:
        print(min_time)

