import sys

def hilbert(x, y, n):
    """Compute the hilbert order of a point (x, y)"""
    if n == 0:
        return 0
    size = 1 << (n - 1)
    quad = 0
    if x & size:
        quad |= 2
    if y & size:
        quad |= 1
    if quad == 0:  # Lower left
        return hilbert(y, x, n - 1)
    elif quad == 1:  # Upper left
        return size * size + hilbert(x, y, n - 1)
    elif quad == 2:  # Lower right
        return 2 * size * size + hilbert(x, y, n - 1)
    else:  # Upper right
        return 3 * size * size + hilbert(size - 1 - y, size - 1 - x, n - 1)

def distance(x1, y1, x2, y2, n):
    """Compute the distance between two points (x1, y1) and (x2, y2)"""
    size = 1 << n
    if x1 < 0 or x1 >= size or y1 < 0 or y1 >= size or x2 < 0 or x2 >= size or y2 < 0 or y2 >= size:
        return abs(x1 - x2) + abs(y1 - y2)
    h1 = hilbert(x1, y1, n)
    h2 = hilbert(x2, y2, n)
    if h1 == h2:
        return distance_inside(x1, y1, x2, y2, n)
    elif abs(h1 - h2) == 1:
        return 1 + distance_inside(x1, y1, exit(x1, y1, n), n) + distance_inside(x2, y2, exit(x2, y2, n), n)
    else:
        e1 = exit(x1, y1, n)
        e2 = exit(x2, y2, n)
        return distance_inside(x1, y1, e1, n) + distance(e1[0], e1[1], e2[0], e2[1], n - 1) + distance_inside(x2, y2, e2, n)

def distance_inside(x1, y1, x2, y2, n):
    """Compute the distance between two points inside the same hilbert curve"""
    size = 1 << n
    if x1 < 0 or x1 >= size or y1 < 0 or y1 >= size or x2 < 0 or x2 >= size or y2 < 0 or y2 >= size:
        return abs(x1 - x2) + abs(y1 - y2)
    h1 = hilbert(x1, y1, n)
    h2 = hilbert(x2, y2, n)
    if h1 == h2:
        return abs(x1 - x2) + abs(y1 - y2)
    else:
        return min(abs(h1 - h2) + distance_inside(x1, y1, exit(x1, y1, n), n) + distance_inside(x2, y2, exit(x2, y2, n), n),
                   distance(x1, y1, x2, y2, n))

def exit(x, y, n):
    """Compute the exit point of a point (x, y)"""
    size = 1 << n
    h = hilbert(x, y, n)
    next_h = h + 1
    if next_h == size * size:
        next_h = h - 1
    return dither(next_h, n)

def dither(h, n):
    """Compute the coordinates of a hilbert order h"""
    if n == 0:
        return (0, 0)
    size = 1 << (n - 1)
    quad = h // (size * size)
    h %= size * size
    if quad == 0:  # Lower left
        (x, y) = dither(h, n - 1)
        return (y, x)
    elif quad == 1:  # Upper left
        (x, y) = dither(h, n - 1)
        return (x, y + size)
    elif quad == 2:  # Lower right
        (x, y) = dither(h, n - 1)
        return (x + size, y + size)
    else:  # Upper right
        (x, y) = dither(h, n - 1)
        return (size - 1 - y + size, size - 1 - x)

def main():
    k = int(sys.stdin.readline().strip())
    for _ in range(k):
        n, x1, y1, x2, y2 = map(int, sys.stdin.readline().strip().split())
        size = 1 << n
        x1 += size // 2
        y1 += size // 2
        x2 += size // 2
        y2 += size // 2
        print(distance(x1, y1, x2, y2, n))

if __name__ == "__main__":
    main()
