        new_direction = (direction - 1) % 4
    elif quadrant == (True, True, False, False):  # Upper right (mirrored)
        new_x, new_y = -y, x
        new_direction = (3 - direction) % 4
    elif quadrant == (True, True, False, True):  # Upper left (mirrored)
        new_x, new_y = x, -y
        new_direction = (direction + 2) % 4
    elif quadrant == (False, True, False, True):  # Lower left (mirrored)
        new_x, new_y = -y, -x
        new_direction = (1 - direction) % 4
    else:  # Lower right (mirrored)
        new_x, new_y = y, -x
        new_direction = (direction + 3) % 4

