        return hilbert_curve(x - half_size, y - half_size, n - 1, (direction + 0) % 4)
    elif x < half_size and y >= half_size:  # Second quadrant
        return hilbert_curve(-y + half_size - 1, x, n - 1, (direction + 3) % 4)
    elif x < half_size and y < half_size:  # Third quadrant
        return hilbert_curve(-x + half_size - 1, -y + half_size - 1, n - 1, (direction + 2) % 4)
    else:  # Fourth quadrant
        return hilbert_curve(y, -x + half_size - 1, n - 1, (direction + 1) % 4)

