from collections import deque

def hilbert_order(x, y, n):
    """Compute the Hilbert order of a point (x, y) at level n."""
    order = 0
    s = 1 << (n - 1)
    while s:
        rx = 1 & (x // s)
        ry = 1 & (y // s)
        order += s * s * ((3 * rx) ^ ry)
        x, y = rot(rx, ry, x % s, y % s, s)
        s >>= 1
    return order

def rot(rx, ry, x, y, s):
    """Rotate (x, y) according to (rx, ry) and s."""
    if ry == 0:
        if rx == 1:
            x = s - 1 - x
            y = s - 1 - y
        return y, x
    return x, y

def hedge_between(x1, y1, x2, y2, n):
    """Check if there's a hedge between (x1, y1) and (x2, y2) at level n."""
    if abs(x1 - x2) + abs(y1 - y2) != 1:
        return True  # Hedge exists if not adjacent
    min_x, max_x = min(x1, x2), max(x1, x2)
    min_y, max_y = min(y1, y2), max(y1, y2)
    level = 1
    while level <= n:
        s = 1 << (level - 1)
        hx1, hy1 = x1 // s, y1 // s
        hx2, hy2 = x2 // s, y2 // s
        h_order1 = hilbert_order(hx1, hy1, level)
        h_order2 = hilbert_order(hx2, hy2, level)
        if h_order1 != h_order2:
            if max_x % s == 0 and max_y % s == 0:
                return True  # Hedge exists
            else:
                return False  # No hedge
        level += 1
    return False  # No hedge at the highest level

def bfs_distance(n, x1, y1, x2, y2):
    """Compute the shortest distance between (x1, y1) and (x2, y2) using BFS."""
    queue = deque([(x1, y1, 0)])
    visited = set((x1, y1))
    while queue:
        x, y, dist = queue.popleft()
        if (x, y) == (x2, y2):
            return dist
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in visited and not hedge_between(x, y, nx, ny, n):
                queue.append((nx, ny, dist + 1))
                visited.add((nx, ny))
    return -1  # No path found

def main():
    k = int(input().strip())
    for _ in range(k):
        n, x1, y1, x2, y2 = map(int, input().strip().split())
        print(bfs_distance(n, x1, y1, x2, y2))

