    """Compute the Hilbert order of a point (x, y) at level n."""
    if n == 0:
        return 0
    m = 1 << (n - 1)
    s = (x >= 0) * 2 + (y >= 0)
    x, y = abs(x), abs(y)
    if x < m and y < m:
        return hilbert(-y, x, n - 1) + (s % 4 == 1 or s % 4 == 2) * (1 << (2 * n - 2))
    elif x < m and y >= m:
        return hilbert(x, y - m, n - 1) + (s % 4 == 0 or s % 4 == 1) * (1 << (2 * n - 2)) + (s % 4 > 1) * (1 << (2 * n - 1))
    elif x >= m and y >= m:
        return hilbert(x - m, y - m, n - 1) + (s % 4 == 0 or s % 4 == 3) * (1 << (2 * n - 2)) + (1 << (2 * n - 1))
