import sys

class FenwickTree:
    def __init__(self, size):
        self.size = size
        self.tree = [0] * (size + 1)

    def update(self, i, val):
        while i <= self.size:
            self.tree[i] += val
            i += i & -i

    def query(self, i):
        res = 0
        while i > 0:
            res += self.tree[i]
            i -= i & -i
        return res

    def range_query(self, i, j):
        return self.query(j) - self.query(i - 1)


def main():
    input = sys.stdin.readline
    N = int(input())
    A = list(map(int, input().split()))
    B = list(map(int, input().split()))

    index_map = {}
    for i, num in enumerate(A):
        if num not in index_map:
            index_map[num] = []
        index_map[num].append(i)

    b_indices = []
    for num in B:
        b_indices.append(index_map[num].pop())

    fenwick_tree = FenwickTree(N)
    for i, idx in enumerate(b_indices):
        fenwick_tree.update(idx + 1, 1)

    dividers = []
    left = 0
    while left < N:
        right = left
        count = 1
        min_idx = b_indices[left] + 1
        max_idx = b_indices[left] + 1
        fenwick_tree.update(b_indices[left] + 1, -1)
        while right + 1 < N and min_idx <= right + 1 <= max_idx:
            if fenwick_tree.range_query(min_idx, max_idx) == 0:
                dividers.append(right + 1)
                left = right + 1
                break
            right += 1
            idx = b_indices[right] + 1
            fenwick_tree.update(idx, -1)
            min_idx = min(min_idx, idx)
            max_idx = max(max_idx, idx)
            count += 1
        else:
            left = right + 1

    output = []
    for i, num in enumerate(B):
        output.append(str(num))
        if i + 1 in dividers:
            output.append('#')

    print(' '.join(output))


if __name__ == '__main__':
    main()
