from collections import deque

def hilbert_maze_instructions(n, memo = {}):
    if n in memo:
        return memo[n]
    if n == 1:
        result = 'A'
    else:
        prev = hilbert_maze_instructions(n-1, memo)
        result = prev.replace('A', 'LBFRAFARFBL').replace('B', 'RAFLBFBLFAR')
    memo[n] = result
    return result

def construct_maze(n):
    instructions = hilbert_maze_instructions(n)
    instructions = instructions.replace('A', '').replace('B', '')
    x, y = 0, 0
    dx, dy = 1, 0
    hedges = set()
    for char in instructions:
        if char == 'F':
            new_x, new_y = x + dx, y + dy
            if dx == 1:
                hedges.add((min(x, new_x), max(x, new_x), max(y, new_y)))
            elif dx == -1:
                hedges.add((min(x, new_x), max(x, new_x), min(y, new_y)))
            elif dy == 1:
                hedges.add((min(y, new_y), max(y, new_y), min(x, new_x)))
            else:
                hedges.add((min(y, new_y), max(y, new_y), max(x, new_x)))
            x, y = new_x, new_y
        elif char == 'R':
            dx, dy = dy, -dx
        elif char == 'L':
            dx, dy = -dy, dx
    return hedges

def bfs_distance(n, x1, y1, x2, y2):
    hedges = construct_maze(n)
    queue = deque([(x1, y1, 0)])
    visited = set((x1, y1))
    while queue:
        x, y, dist = queue.popleft()
        if (x, y) == (x2, y2):
            return dist
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            new_x, new_y = x + dx, y + dy
            if (new_x, new_y) not in visited:
                if dx == 0:
                    if (min(y, new_y), max(y, new_y), x) not in hedges:
                        queue.append((new_x, new_y, dist + 1))
                        visited.add((new_x, new_y))
