from collections import deque

def hilbert_curve(order):
    """Generate the Hilbert curve instructions for a given order."""
    s = 'A'
    for _ in range(order):
        s = s.replace('A', 'LBFRAFARFBL').replace('B', 'RAFLBFBLFAR')
    s = s.replace('A', '').replace('B', '')
    return s

def preprocess_hilbert_curves(max_order):
    """Preprocess and store the Hilbert curve instructions up to a given order."""
    curves = {}
    for order in range(1, max_order + 1):
        curves[order] = hilbert_curve(order)
    return curves

def get_position_and_direction(instructions):
    """Get the final position and direction after following the Hilbert curve instructions."""
    x, y = 0, 0
    dx, dy = 1, 0
    for instruction in instructions:
        if instruction == 'F':
            x, y = x + dx, y + dy
        elif instruction == 'R':
            dx, dy = dy, -dx
        elif instruction == 'L':
            dx, dy = -dy, dx
    return x, y, dx, dy

def get_hilbert_curve_properties(order, curves):
    """Get the properties of the Hilbert curve for a given order."""
    instructions = curves[order]
    x, y, dx, dy = get_position_and_direction(instructions)
    size = max(abs(x), abs(y)) + 1
    return size, dx, dy

def is_hedge_between(x1, y1, x2, y2, n, curves):
    """Check if there is a hedge between two adjacent cells in the Hilbert curve maze."""
    if abs(x1 - x2) + abs(y1 - y2) != 1:
        return True  # Not adjacent
    for order in range(n, 0, -1):
        size, dx, dy = get_hilbert_curve_properties(order, curves)
        x1_mod, y1_mod = x1 % size, y1 % size
        x2_mod, y2_mod = x2 % size, y2 % size
        x1_div, y1_div = x1 // size, y1 // size
        x2_div, y2_div = x2 // size, y2 // size
        if (x1_div, y1_div) != (x2_div, y2_div):
            # Different cells at this order, check if there's a hedge
            quadrant1 = get_quadrant(x1_mod, y1_mod, size, dx, dy)
            quadrant2 = get_quadrant(x2_mod, y2_mod, size, dx, dy)
            if quadrant1 != quadrant2:
                return True  # Hedge between different quadrants
        x1, y1 = x1_div, y1_div
        x2, y2 = x2_div, y2_div
