    """Determine the quadrant of a point within a Hilbert curve cell."""
    x0, y0 = size // 2, size // 2
    if x < x0 and y < y0:
        return 0
    elif x >= x0 and y < y0:
        return 1
    elif x >= x0 and y >= y0:
        return 2
    else:
        return 3

