def hilbert_order(x, y, n):
    """Compute the hilbert order of a point (x, y)"""
    order = 0
    s = 1 << (n - 1)
    while s > 0:
        rx = 1 & (x // s)
        ry = 1 & (y // s)
        order += s * s * ((3 * rx) ^ ry)
        x, y = rot(x, y, s, rx, ry)
        s //= 2
    return order

def rot(x, y, s, rx, ry):
    """Rotate (x, y) according to the hilbert curve"""
    if ry == 0:
        if rx == 1:
            x = s - 1 - x
            y = s - 1 - y
        return y, x
    return x, y

def distance(x1, y1, x2, y2):
    """Compute the Manhattan distance between two points"""
    return abs(x1 - x2) + abs(y1 - y2)

def solve(n, x1, y1, x2, y2):
    """Compute the shortest distance between two points in the Hilbert's Hedge Maze"""
    d = 1 << n
    if (abs(x1) >= d or abs(y1) >= d or abs(x2) >= d or abs(y2) >= d):
        return distance(x1, y1, x2, y2)
    o1 = hilbert_order(x1, y1, n)
    o2 = hilbert_order(x2, y2, n)
    if o1 > o2:
