            mid = (start + end) // 2
            self.build_tree(nums, 2 * node + 1, start, mid)
            self.build_tree(nums, 2 * node + 2, mid + 1, end)
            self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2]

    def query(self, node, start, end, left, right):
        if right < start or end < left:
            return 0
        if left <= start and end <= right:
            return self.tree[node]
        mid = (start + end) // 2
        p1 = self.query(2 * node + 1, start, mid, left, right)
        p2 = self.query(2 * node + 2, mid + 1, end, left, right)
        return p1 + p2

    def update(self, node, start, end, idx, val):
        if start == end:
            self.tree[node] = val
        else:
            mid = (start + end) // 2
            if start <= idx and idx <= mid:
                self.update(2 * node + 1, start, mid, idx, val)
            else:
                self.update(2 * node + 2, mid + 1, end, idx, val)
            self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2]


def main():
    import sys
    input = sys.stdin.readline

    n, c = map(int, input().split())
    w = list(map(int, input().split()))

    seg_tree = SegmentTree(w)
    count = [0] * n

    s, e = 0, 0
    while s < n:
        if e + 1 < n and seg_tree.query(0, 0, n - 1, s, e + 1) <= c:
            e += 1
        else:
            s += 1
        if s - 1 >= 0 and s - 1 <= e:
            count[s - 1] -= 1
        if s <= e:
            count[e] += e - s + 1

        if e >= n:
            s += 1
        if s > e:
            e = s

    print(*count, sep='\n')


if __name__ == "__main__":
