def simulate_sliding_window(N, C, prefix_sums):
    counts = [0] * N
    s, e = 0, 0
    while s < N:
        while e < N and prefix_sums[e + 1] - prefix_sums[s] <= C:
            e += 1
        for i in range(s, e):
            counts[i] += e - i
        if s < e:
            counts[e - 1] += 1  # Corrected the index here
        s += 1
    return counts

